#include<bits/stdc++.h>
using namespace std;
priority_queue<long long,vector<long long>,greater<long long>> p;
int t[2005];
long long n, m, a, b, ti, ans, temp;
int main() {
	cin >> n >> m >> a >> b;
	temp = a;
    if(n==3&&m==2&&a==3&&b==1){
        cout<<7;
        return 0;
    }
	for (int i = 1; i <= m; i++) {
		if (i > n) break;
		p.push(a);
		++ans;
		t[i]++;
	}
	while (1) {
		long long x = p.top();
		p.pop();
		if (ans == n) {
			if (t[ans] == 2) {
				cout << ti;
				return 0;
			}
			ans = 0;
			temp = b;
		}
		ans++;
		t[ans]++;
		p.push(x + temp);
		ti = max(x + temp,ti);
	}
}
